import java.util.Scanner;
public class Main {
    static final long MOD = 1000000007;
    public static long power(long x, long y, long p)
    {
        long res = 1;
        x = x % p;
        while (y > 0)
        {
            if (y % 2 == 1)
                res = (res * x) % p;
            y = y >> 1;
            x = (x * x) % p;
        }
        return res;
    }
    public static long modInverse(long n, long p)
    {
        return power(n, p - 2, p);
    }
    public static long nCrModPFermat(long n, long r, long p)
    {
        if (n < r)
            return 0;
        if (r == 0)
            return 1;
        long[] fac = new long[(int)n + 1];
        fac[0] = 1;
        for (int i = 1; i <= n; i++)
            fac[i] = (fac[i - 1] * i) % p;
        return (fac[(int)n] * modInverse(fac[(int)r], p) % p
                * modInverse(fac[(int)n - (int)r], p) % p)
               % p;
    }
    public static void main(String[] args)
    {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0)
        {
            long N = sc.nextLong();
            long K = sc.nextLong();
            long sum = 0;
            for (int i = 1; i <= N; i++)
            {
                for (int j = 1; j <= N; j++)
                {
                    long x = Math.abs(K - 0);
                    long y = Math.abs(j - i);
                    sum = (sum + nCrModPFermat(x + y, x, MOD)) % MOD;
                }
            }
            System.out.println(sum);
        }
    }
}

