def power(x, y, p):
    res = 1
    x = x % p
    while y > 0:
        if y % 2 == 1:
            res = (res * x) % p
        y = y >> 1
        x = (x * x) % p
    return res

def mod_inverse(n, p):
    return power(n, p - 2, p)

def ncr_mod_p_fermat(n, r, p):
    if n < r:
        return 0
    if r == 0:
        return 1
    fac = [1] * (int(n) + 1)
    for i in range(1, int(n) + 1):
        fac[i] = (fac[i - 1] * i) % p
    return (fac[int(n)] * mod_inverse(fac[int(r)], p) % p
            * mod_inverse(fac[int(n) - int(r)], p) % p)
           % p

def main():
    MOD = 1000000007
    T = int(input())
    for _ in range(T):
        N, K = map(int, input().split())
        sum = 0
        for i in range(1, N + 1):
            for j in range(1, N + 1):
                x = abs(K - 0)
                y = abs(j - i)
                sum = (sum + ncr_mod_p_fermat(x + y, x, MOD)) % MOD
        print(sum)

def solve():
    main()
if __name__ == '__main__':
    solve()

